import{bV as n,aL as s,u as t,G as e}from"./chunks/framework.BQalybiP.js";const g=JSON.parse('{"title":"Level1 - Pronunciation","description":"","frontmatter":{"date":"2026-05-07T08:26:06.000Z","title":"Level1 - Pronunciation","categories":["英语","Speaking"]},"headers":[],"relativePath":"06.英语/Speaking/03.Level1 - Pronunciation.md","filePath":"06.英语/Speaking/03.Level1 - Pronunciation.md"}'),a={name:"06.英语/Speaking/03.Level1 - Pronunciation.md"};function r(p,o,i,h,c,l){return s(),t("div",null,[...o[0]||(o[0]=[e('<h1 id="pronunciation-consonants" tabindex="-1">Pronunciation- Consonants <a class="header-anchor" href="#pronunciation-consonants" aria-label="Permalink to &quot;Pronunciation- Consonants&quot;">​</a></h1><h3 id="do-you-know-what-a-consonant-is" tabindex="-1">Do you know what a consonant is? <a class="header-anchor" href="#do-you-know-what-a-consonant-is" aria-label="Permalink to &quot;Do you know what a consonant is?&quot;">​</a></h3><p>A consonant is a speech sound that is made by partially or completely blocking the flow of air as it passes through your mouth. To produce a consonant, your tongue, lips, teeth, or palate create an obstruction. (palate /ˈpælət/ 腭 ; obstruction /əbˈstrʌkʃ(ə)n/ 堵塞 )</p><p>The opposite of a consonant is a vowel (A, E, I, O, U — and sometimes Y), where air flows freely without blockage. (blockage /ˈblɑːkɪdʒ/ 堵塞，阻塞 )</p><h3 id="can-you-name-some-consonants" tabindex="-1">Can you name some consonants? <a class="header-anchor" href="#can-you-name-some-consonants" aria-label="Permalink to &quot;Can you name some consonants?&quot;">​</a></h3><p>Voiced /vɔɪst/ 浊音的；有声的</p><p>Unvoiced /ˌʌnˈvɔɪst/ 清音的</p><p>Voiceless /ˈvɔɪsləs/ 无声的；清音的</p><p>How do you pronounce /s/ as in “sit” and /z/ as in “zoo”?</p><p>How do you pronounce /th/ as in “think” and “them”?</p><p>/s/ /z/</p><p>/θ/ /ð/</p><p>Unvoiced vs Voiced</p><p>/θ/ and /ð/ : the very tip of the tongue should come between the teeth to make this sound.</p><p><strong>- s (as in sit):</strong></p><p>Examples: sit, sun, soup, school</p><p><strong>- z (as in zoo):</strong></p><p>Examples: zoo, zebra, zero, zipper</p><p><strong>- th (unvoiced, as in think):</strong></p><p>Examples: think, three, thousand, Thursday</p><p><strong>- th (voiced, as in this):</strong></p><p>Examples: this, that, they, though</p><h3 id="identifying-the-different-consonants" tabindex="-1">Identifying the different consonants. <a class="header-anchor" href="#identifying-the-different-consonants" aria-label="Permalink to &quot;Identifying the different consonants.&quot;">​</a></h3><p><strong>Pronouncing the voiced and unvoiced consonants.</strong></p><p><strong>International Phonetic Alphabet</strong></p><p>How many IPA symbols are there in English?</p><p><strong>How many vowel sounds are there?</strong></p><p>-20 vowel sounds (12 monophthongs and 8 diphthongs).</p><p><strong>How many consonant sounds are there?</strong></p><p>- 24 consonant sounds.</p><p><strong>Consonants</strong></p><p>/p/ /b/ /t/ /d/ /tʃ/ /dʒ/</p><p>/k/ /ɡ/ /f/ /v/</p><p>/θ/ /ð/ /s/ /z/</p><p>Shall /ʃ/ television /ʒ/</p><p>/m/ /n/ /ŋ/</p><p>/h/ /l/ /r/ /w/ /j/</p><p>Another four Consonants (48个音标版本里的额外4个辅音)：</p><p>/ts/ /dz/ /tr/ /dr/</p><p>Cats hands tree drive</p><p><strong>/ʃ/ vs. /ʒ/</strong></p><p>ship /ʃɪp/</p><p>shy /ʃaɪ/ 害羞的</p><p>shout /ʃaʊt/ 喊叫</p><p>shut /ʃʌt/ 关闭</p><p>fish /fɪʃ/ 鱼</p><p>dish /dɪʃ/ 盘子；一道菜</p><p>fashion /ˈfæ.ʃən/ 时尚</p><p>nation /ˈneɪ.ʃən/ 国家</p><p>attention /əˈten.ʃən/ 注意力</p><p>election /ɪˈlek.ʃən/ 选举</p><p>ocean /ˈəʊ.ʃən/ 海洋</p><p>Usually</p><p>Measure /ˈmeʒə(r)/ 测量</p><p>Pleasure /ˈpleʒər/</p><p>Casual /ˈkæ.ʒu.əl/ 随意的</p><p>Asia /ˈeɪ.ʒə/ 亚洲</p><h3 id="consonants-can-be-voiced-or-unvoiced" tabindex="-1">Consonants can be voiced or unvoiced. <a class="header-anchor" href="#consonants-can-be-voiced-or-unvoiced" aria-label="Permalink to &quot;Consonants can be voiced or unvoiced.&quot;">​</a></h3><p><strong>Voiced sounds:</strong></p><p>You vocal cords vibrate when you say these.</p><p>For example: z , b , v</p><p><strong>Unvoiced sounds:</strong></p><p>You vocal cords do not vibrate to say these.</p><p>For example: s, p, f</p><p>Put your hand on your throat to feel the vocal cords vibrate when you say them.</p><h3 id="can-you-sort-these-voiced-and-unvoiced-consonants" tabindex="-1">Can you sort these voiced and unvoiced consonants? <a class="header-anchor" href="#can-you-sort-these-voiced-and-unvoiced-consonants" aria-label="Permalink to &quot;Can you sort these voiced and unvoiced consonants?&quot;">​</a></h3><p><strong>sort 把……分类</strong></p><ul><li><p>Unvoiced: pen, two, keep, five, sing, think, she, chair</p></li><li><p>Voiced: back, dog, get, very, zero, them, usual, Jane</p></li></ul><p>Unvoiced(9个）: /t/ /ʃ/ /θ/ /f/ /s/ /p/ /k/ /tʃ/ /h/</p><p><strong>[Another two consonants “ /ts/ and /tr/ ” are also unvoiced. ]</strong></p><p>Voiced: /b/ /d/ /dʒ/ /ɡ/ /v/ /ð/ /z/ /ʒ/ /m/ /n/ /ŋ/ /l/ /r/ /w/ /j/</p><h3 id="each-sentence-has-a-different-voiced-unvoiced-consonant-pair" tabindex="-1">Each sentence has a different voiced/unvoiced consonant pair. <a class="header-anchor" href="#each-sentence-has-a-different-voiced-unvoiced-consonant-pair" aria-label="Permalink to &quot;Each sentence has a different voiced/unvoiced consonant pair.&quot;">​</a></h3><p>Keep the shape of your mouth the same for the two consonant sounds!</p><p>1.<strong>Sh</strong>e u<strong>s</strong>ually starts at ten.</p><p>2.<strong>Th</strong>ey will meet at <strong>th</strong>ree.</p><p>3.The shoe<strong>s</strong> are too <strong>s</strong>mall.</p><p>4.They have <strong>t</strong>wo <strong>b</strong>ig dogs.</p><p>5.<strong>C</strong>an you buy <strong>g</strong>rapes?</p><p>6.Please <strong>b</strong>ring a <strong>p</strong>en.</p><p>7.The <strong>g</strong>ym has ben<strong>ch</strong>es.</p><p>8.They are <strong>v</strong>ery <strong>f</strong>unny.</p><p><strong>Consonant pairs</strong> are two sounds that are produced with the same mouth position but differ in voicing.<strong>辅音对</strong>是两种用相同口型发出、但在清浊上不同的声音。</p><p>Take the pair /p/ and /b/ for example. Your lips come together in the same way, but /p/ is voiceless (only air) and /b/ is voiced (with vocal cord vibration).以 /p/ 和 /b/ 这对为例。你的嘴唇闭合方式是一样的，但 /p/ 是清辅音（只有气流），而 /b/ 是浊辅音（声带振动）。</p><p><strong>The 8 Main Consonant Pairs</strong></p><ol><li><p><strong>/ʒ/ /ʃ/</strong></p></li><li><p><strong>/ð/ /θ/</strong></p></li><li><p><strong>/z/ /s/</strong></p></li><li><p><strong>/d/ /t/</strong></p></li><li><p><strong>/g/ /k/</strong></p></li><li><p><strong>/b/ /p/</strong></p></li><li><p><strong>/dʒ/ /tʃ/</strong></p></li><li><p><strong>/v/ /f/</strong></p></li></ol><p><strong>Voicing of voiceless consonants 清辅音浊化</strong></p><p><strong>Skirt （sk--&gt; sg)</strong></p><p><strong>Speak (sp--&gt; sb )</strong></p><p><strong>Star ( st--&gt; sd)</strong></p><p><strong>Street (Str--&gt; sdr )</strong></p><p><strong>Leaf -&gt; leaves</strong></p><p><strong>Let’s try tongue twisters!</strong> <strong>(Tongue twister /ˈtʌŋ twɪstə(r)/ 绕口令)</strong></p><p><strong>Say the sentences slowly and correctly.</strong></p><p><strong>Say the sentences as quickly as possible!</strong></p><ol><li>How many cookies could a good cook cook if a good cook could cook cookies?</li></ol><p>​ (this sentence focuses on /k/ vs /g/.)</p><ol start="2"><li>She sells seashells by the seashore,</li></ol><p>​ The shells she sells are seashells, I’m sure.</p><p>​ So if she sells seashells on the seashore,</p><p>​ Then I’m sure she sells seashore shells.</p><p>​ ( this sentence focuses on /s/ /z/ /ʃ/ . )</p><p>​ Seashell /ˈsiːʃel/海贝壳;</p><p>​ Seashore /ˈsiːʃɔːr/ 海岸；海滨</p><ol start="3"><li>They thought about these three thousand things for those thirty-three thousand hours.</li></ol><p>​ ( This sentence focuses on /θ/ vs /ð/. )</p><p>​ think - thought /θɔːt/</p><h3 id="identify-the-different-consonants" tabindex="-1">Identify the different consonants. <a class="header-anchor" href="#identify-the-different-consonants" aria-label="Permalink to &quot;Identify the different consonants.&quot;">​</a></h3><p><strong>Pronounce the voiced and unvoiced consonants.</strong></p><p><img src="https://picgo-storage-typora.oss-cn-shanghai.aliyuncs.com/English-Pronunciation-2.jpg" alt="sounds-2"></p><p><img src="https://picgo-storage-typora.oss-cn-shanghai.aliyuncs.com/English-Pronunciation-1.jpg" alt="sounds-1"></p>',110)])])}const u=n(a,[["render",r]]);export{g as __pageData,u as default};
